def has_child_field(doctype, fieldname):
    try:
        meta = frappe.get_meta(doctype)
        return meta.has_field(fieldname)
    except Exception:
        return False


def first_existing_value(doctype, docname, candidates):
    for f in candidates:
        try:
            val = frappe.db.get_value(doctype, docname, f)
            if val is not None and val != "":
                return val
        except Exception:
            pass
    return None


def get_company_abbr(company_name):
    abbr = ""
    try:
        abbr = frappe.db.get_value("Company", company_name, "abbr") or ""
    except Exception:
        abbr = ""
    return (abbr or "").strip()


def get_mapping_account(base_key, company_name):
    abbr = get_company_abbr(company_name)
    keys = []
    if abbr:
        keys.append(base_key + "-" + abbr)
    keys.append(base_key)

    rows = []
    try:
        rows = frappe.get_all(
            "GL Account Mapping",
            filters=[
                ["company", "=", company_name],
                ["is_active", "=", 1],
                ["mapping_key", "in", keys],
            ],
            fields=["account", "mapping_key", "priority"],
            order_by="priority desc, creation desc",
            limit_page_length=1
        )
    except Exception:
        rows = []

    if rows and rows[0].get("account"):
        return rows[0]["account"]
    return ""


def require_mapping(base_key, company_name, friendly_name):
    acc = get_mapping_account(base_key, company_name)
    if not acc:
        frappe.throw("Missing GL Mapping: " + base_key + " (" + friendly_name + ") for: " + company_name)
    return acc


def get_account_type(account_name):
    try:
        return frappe.db.get_value("Account", account_name, "account_type") or ""
    except Exception:
        return ""


def is_rp_account(account_name):
    at = (get_account_type(account_name) or "").strip()
    return at in ("Receivable", "Payable")


def append_je_row(je, row, party_type_val=None, party_val=None):
    if party_type_val and party_val and is_rp_account(row.get("account")):
        row["party_type"] = party_type_val
        row["party"] = party_val
    else:
        if "party_type" in row:
            row.pop("party_type", None)
        if "party" in row:
            row.pop("party", None)
    je.append("accounts", row)


def is_pharmacy_customer(customer):
    try:
        ctype = frappe.db.get_value("Customer", customer, "custom_customers_type") or ""
    except Exception:
        ctype = ""
    return ((ctype or "").strip().lower() == "pharmacy")


def fallback_debtors(company_name):
    abbr = get_company_abbr(company_name)

    if abbr:
        acc = frappe.db.get_value(
            "Account",
            {"company": company_name, "is_group": 0, "name": "Debtors - " + abbr},
            "name"
        )
        if acc:
            return acc

        acc = frappe.db.get_value(
            "Account",
            {"company": company_name, "is_group": 0, "name": "المدينون - " + abbr},
            "name"
        )
        if acc:
            return acc

    acc2 = frappe.db.get_value(
        "Account",
        {"company": company_name, "is_group": 0, "name": ["like", "%Debtors%"]},
        "name"
    )
    if acc2:
        return acc2

    acc3 = frappe.db.get_value(
        "Account",
        {"company": company_name, "is_group": 0, "name": ["like", "%المدينون%"]},
        "name"
    )
    if acc3:
        return acc3

    recs = frappe.get_all(
        "Account",
        filters={
            "company": company_name,
            "is_group": 0,
            "account_type": "Receivable",
            "name": ["not like", "%جزاء%"]
        },
        fields=["name"],
        order_by="name asc",
        limit_page_length=1
    )
    if recs and recs[0].get("name"):
        return recs[0]["name"]

    frappe.throw("Missing RECEIVABLE mapping and could not auto-find Debtors account for " + company_name)


