except Exception:
    has_customer_field = False

customer_val = ""
if has_customer_field:
    try:
        customer_val = doc.customer or ""
    except Exception:
        customer_val = ""

is_draw = True if not customer_val else False

# -------------------- Accounts --------------------
agent_payable = require_mapping("EMPLOYEE_DRAW", company, "Agent Commission Payable (Draw/Clearing)")

receivable = ""
commission_expense = ""
commission_payable = ""

if not is_draw:
    receivable = get_mapping_account("RECEIVABLE", company) or ""
    if not receivable:
        receivable = fallback_debtors(company)

    commission_expense = get_mapping_account("COMMISSION_EXPENSE", company) or ""
    commission_payable = get_mapping_account("COMMISSION_PAYABLE", company) or ""

# -------------------- Commission (only for collection) --------------------
pct = 0.0
commission_amt = 0.0

if not is_draw:
    is_pharmacy = is_pharmacy_customer(customer_val)

    user_id = ""
    if doc.employee:
        user_id = frappe.db.get_value("Employee", doc.employee, "user_id") or ""
    if not user_id:
        user_id = doc.owner or frappe.session.user

    pct1_fields = ["percentage_1", "custom_percentage_1"]
    pct2_fields = ["percentage_2", "custom_percentage_2"]
    pct_val = None

    if is_pharmacy:
        pct_val = first_existing_value("User", user_id, pct1_fields)
    else:
        pct_val = first_existing_value("User", user_id, pct2_fields)

    if pct_val is None and doc.employee:
        if is_pharmacy:
            pct_val = first_existing_value("Employee", doc.employee, pct1_fields)
        else:
            pct_val = first_existing_value("Employee", doc.employee, pct2_fields)

    pct = float(pct_val or doc.agent_percentage or 0)
    commission_amt = round(amount * (pct / 100.0), 3) if pct > 0 else 0.0

doc.db_set("agent_percentage", pct)
doc.db_set("agent_commission", commission_amt)

# -------------------- JE --------------------
je = frappe.new_doc("Journal Entry")
je.company = company
je.posting_date = doc.posting_date or frappe.utils.nowdate()
je.user_remark = "اعتماد تحصيل: " + doc.name + " | واصل: " + (doc.receipt_no or "")

has_emp_dim = has_child_field("Journal Entry Account", "employee")
has_cc_field = has_child_field("Journal Entry Account", "cost_center")

def apply_dims(row):
    if has_cc_field:
        row["cost_center"] = final_cc
    if has_emp_dim and doc.employee:
        row["employee"] = doc.employee
    return row

if is_draw:
    if not doc.employee:
        frappe.throw("employee is required for DRAW process: " + doc.name)

    append_je_row(
        je,
        apply_dims({"account": agent_payable, "debit_in_account_currency": amount}),
        party_type_val="Employee",
        party_val=doc.employee
    )
    append_je_row(
        je,
        apply_dims({"account": doc.bank, "credit_in_account_currency": amount})
    )

else:
    append_je_row(
        je,
        apply_dims({"account": doc.bank, "debit_in_account_currency": amount})
    )
    append_je_row(
        je,
        apply_dims({"account": receivable, "credit_in_account_currency": amount}),
        party_type_val="Customer",
        party_val=customer_val
    )

    if commission_amt > 0:
        if not commission_expense or not commission_payable:
            frappe.throw("Commission mappings missing: COMMISSION_EXPENSE and/or COMMISSION_PAYABLE for " + company)

        append_je_row(
            je,
            apply_dims({"account": commission_expense, "debit_in_account_currency": commission_amt})
        )
        append_je_row(
            je,
            apply_dims({"account": commission_payable, "credit_in_account_currency": commission_amt}),
            party_type_val="Employee",
            party_val=doc.employee
        )

je.insert(ignore_permissions=True)
je.submit()

# -------------------- LOCK + SUBMIT DOC (CORRECT WAY) --------------------
doc.l_reconciled = 1
doc.reconcile_batch = je.name

doc.flags.ignore_permissions = True
doc.save()

if int(doc.docstatus or 0) == 0:
