f = frappe.form_dict

DT = "LMT Debt Collection"

def has_field(dt, fieldname):
    return bool(frappe.db.exists("DocField", {"parent": dt, "fieldname": fieldname}))

def safe_int(x):
    try:
        return int(x)
    except Exception:
        return 0

# -------- read params --------
emp          = (f.get("employee")      or "").strip()
draw         = (f.get("draw")          or "").strip()
customer     = (f.get("customer")      or "").strip()
customer_type= (f.get("customer_type") or "").strip()
s_date       = (f.get("start_date")    or "").strip()
e_date       = (f.get("end_date")      or "").strip()
month        = (f.get("month")         or "").strip()
location     = (f.get("location")      or "").strip()
region       = (f.get("region")        or "").strip()

# -------- conditions --------
conditions = {"docstatus": 1}

if s_date and e_date and has_field(DT, "posting_date"):
    conditions["posting_date"] = ["between", [s_date, e_date]]
elif month and has_field(DT, "posting_date"):
    year = frappe.utils.getdate().year
    m = safe_int(month)
    if 1 <= m <= 12:
        start = "%04d-%02d-01" % (year, m)
        end = frappe.utils.get_last_day(start)
        conditions["posting_date"] = ["between", [start, end]]

# -------- agent field: agent_name is المندوب (priority), fallback to others --------
agent_field = None
for cand in ["agent_name", "employee", "agent", "collector", "sales_person",
             "salesperson", "user", "agent_user", "custom_agent", "custom_employee"]:
    if has_field(DT, cand):
        agent_field = cand
        break

# apply agent filter
# agent_name stores user email, not Employee ID — convert before filtering
if emp and agent_field:
    if agent_field == "agent_name":
        emp_user_id = frappe.db.get_value("Employee", emp, "user_id")
        if emp_user_id:
            conditions["agent_name"] = emp_user_id
        else:
            conditions["agent_name"] = "__none__"
    else:
        conditions[agent_field] = emp

# location filter: cost_center -> warehouse -> user email -> agent_name
if location:
    users_in_loc = frappe.db.sql(
        "SELECT u.name FROM `tabUser` u INNER JOIN `tabWarehouse` w ON w.name = u.warehouse WHERE w.custom_custom_cost_center = %s",
        location, pluck="name"
    )
    if users_in_loc:
        if emp:
            # emp is Employee ID — get its user_id email
            emp_email = frappe.db.get_value("Employee", emp, "user_id") or ""
            if emp_email not in users_in_loc:
                conditions["agent_name"] = ["in", ["__none__"]]
            # else: agent filter already set correctly above
        else:
            conditions["agent_name"] = ["in", users_in_loc]
    else:
        conditions["agent_name"] = ["in", ["__none__"]]

# customer filter
if customer and has_field(DT, "customer"):
    conditions["customer"] = customer

# region via Customer -> Address -> county
if region and has_field(DT, "customer"):
    custs_in_region = frappe.db.sql("""
        SELECT DISTINCT dl.link_name
        FROM `tabAddress` a
        JOIN `tabDynamic Link` dl ON dl.parent = a.name
        WHERE dl.link_doctype = 'Customer'
        AND CONCAT(a.city, ' - ', a.county) = %s
    """, region, pluck="link_name")
    if "customer" in conditions and isinstance(conditions["customer"], list) and conditions["customer"][0] == "in":
        inter = list(set(conditions["customer"][1]).intersection(set(custs_in_region)))
        conditions["customer"] = ["in", inter or ["__none__"]]
    else:
        conditions["customer"] = ["in", custs_in_region or ["__none__"]]

# customer type via Customer.custom_customers_type
if customer_type and has_field(DT, "customer"):
    custs2 = frappe.get_all("Customer", filters={"custom_customers_type": customer_type},
                            pluck="name", limit_page_length=5000)
    if "customer" in conditions and isinstance(conditions["customer"], list) and conditions["customer"][0] == "in":
        inter = list(set(conditions["customer"][1]).intersection(set(custs2)))
        conditions["customer"] = ["in", inter or ["__none__"]]
    elif "customer" not in conditions:
        conditions["customer"] = ["in", custs2 or ["__none__"]]

# ── FIX: draw filter uses action_type field ("سحب" = draw record) ──
if draw and has_field(DT, "action_type"):
    if draw == "with_draw":
        conditions["action_type"] = "سحب"
    elif draw == "no_draw":
        conditions["action_type"] = ["!=", "سحب"]

# -------- fields to fetch --------
fields = ["name"]
if has_field(DT, "posting_date"):
    fields.append("posting_date")

# ── include action_type so JS can detect draw rows ──
for fn in ["action_type", "customer", "amount", "payment_type", "receipt_no", "receipt_uid",
           "agent_commission", "percent_cust_sum", "sum_draws", "cost_center"]:
    if has_field(DT, fn):
        fields.append(fn)

if agent_field and agent_field not in fields:
    fields.append(agent_field)
if "owner" not in fields:
    fields.append("owner")

entries = frappe.get_all(
    DT,
    filters=conditions,
    fields=fields,
    order_by=("posting_date desc" if has_field(DT, "posting_date") else "modified desc"),
    limit_page_length=2000
)

# -------- build maps --------
employee_ids = set()
user_ids = set()

for d in entries:
    av = d.get(agent_field) if agent_field else None
    if av:
        if isinstance(av, str) and ("@" in av or av == "Administrator"):
            user_ids.add(av)
        else:
            employee_ids.add(av)
    if d.get("owner"):
        user_ids.add(d.get("owner"))

user_to_emp = {}
if user_ids:
    emp_by_user = frappe.get_all(
        "Employee",
        filters={"user_id": ["in", list(user_ids)]},
        fields=["name", "employee_name", "user_id"],
        limit_page_length=5000
    )
    for r in emp_by_user:
        user_to_emp[r["user_id"]] = r["name"]
        employee_ids.add(r["name"])

emp_names = {}
if employee_ids:
    for r in frappe.get_all("Employee",
                            filters={"name": ["in", list(employee_ids)]},
                            fields=["name", "employee_name"],
