# Safe Exec friendly: no imports, no frappe.parse_json, no tuple-unpacking, no str.format, no f-strings

# ==========================================================
# API Name: lmt_warehouse_orders
# Purpose:
# - Return Sales Orders for warehouse page
# - ABSOLUTE restriction:
#   If user has role "Warehouse User" => ONLY warehouses from User Permission (Allow=Warehouse)
# ==========================================================

def parse_json_list_of_strings(raw, default_value=None):
    if default_value is None:
        default_value = []
    if raw is None:
        return default_value

    if isinstance(raw, (list, tuple)):
        out0 = []
        for x in raw:
            s0 = str(x).strip()
            if s0:
                out0.append(s0)
        return out0

    s = str(raw).strip()
    if not s:
        return default_value

    if s[0] == "[" and s[-1] == "]":
        inner = s[1:-1].strip()
        if not inner:
            return []
        out = []
        cur = ""
        in_q = False
        q_char = ""
        esc = False

        for ch in inner:
            if esc:
                cur += ch
                esc = False
                continue
            if ch == "\\":
                esc = True
                continue

            if in_q:
                if ch == q_char:
                    in_q = False
                else:
                    cur += ch
            else:
                if ch == "'" or ch == '"':
                    in_q = True
                    q_char = ch
                elif ch == ",":
                    val = cur.strip()
                    if val:
                        out.append(val)
                    cur = ""
                else:
                    if ch not in (" ", "\t", "\n", "\r"):
                        cur += ch

        val = cur.strip()
        if val:
            out.append(val)

        out2 = []
        for x in out:
            x2 = str(x).strip()
            if x2:
                out2.append(x2)
        return out2

    out3 = []
    parts = s.split(",")
    for p in parts:
        p2 = str(p).strip()
        if p2:
            out3.append(p2)
    return out3


