        SELECT role
        FROM `tabHas Role`
        WHERE parent = %(user)s
          AND parenttype = 'User'
        LIMIT 500
    """, {"user": user}, as_dict=True) or []
    out = []
    for r in rows:
        role = (r.get("role") or "").strip()
        if role and role not in out:
            out.append(role)
    return out

