SYSTEM_ACTIONS = ["سحب", "خصم تسوية"]   

def get_latest_range(user, initials, receipt_no_int=None):
    if receipt_no_int is not None:
        rows = frappe.get_all(
            "LMT Receipt Counter",
            filters={
                "docstatus": 1,
                "assigned_user": user,
                "user_initials": initials,
                "min_receipt_number": ["<=", receipt_no_int],
                "max_receipt_number": [">=", receipt_no_int]
            },
            fields=["name", "min_receipt_number", "max_receipt_number", "posting_date"],
            limit_page_length=1
        )
        if rows:
            return rows[0]
    rows = frappe.get_all(
        "LMT Receipt Counter",
        filters={
            "docstatus": 1,
            "assigned_user": user,
            "user_initials": initials
        },
        fields=["name", "min_receipt_number", "max_receipt_number", "posting_date"],
        order_by="posting_date desc, modified desc",
        limit_page_length=1
    )
    return rows[0] if rows else None

def is_used(uid, exclude_name):
