        FROM `tabLMT Order`
        WHERE customer_key=%s AND agent_email=%s AND order_status='Complete'
    """, (ckey, user), as_dict=True)
    payments = frappe.db.sql("""
        SELECT date, receipt_number as ref, received,
               COALESCE(custom_settlement_discount,0) as discount
        FROM `tabLMT Payment`
        WHERE customer_key=%s AND agent_email=%s
    """, (ckey, user), as_dict=True)

    all_rows = []
    for o in orders:
        amt = float(o.amount or 0)
        if o.trans_type == "ترجيع":
            # FIX: total_cost is already negative — use abs() for credit column
            all_rows.append({
                "date": o.date, "ref": o.ref or "",
                "trans_type": "ترجيع",
                "debit": 0.0, "credit": abs(amt), "discount": 0.0,
                "row_type": "return"
            })
        else:
            all_rows.append({
                "date": o.date, "ref": o.ref or "",
                "trans_type": o.trans_type or "بيع",
                "debit": amt, "credit": 0.0, "discount": 0.0,
                "row_type": "order"
            })

    for p in payments:
        recv = float(p.received or 0)
        disc = float(p.discount or 0)
        ref  = str(p.ref or "")
        if ref == "0" or recv < 0:
            opening = recv * -1 if recv < 0 else recv
            all_rows.append({
                "date": p.date, "ref": "الديون السابقة",
                "trans_type": "الديون السابقة",
                "debit": opening, "credit": 0.0, "discount": 0.0,
                "row_type": "opening"
            })
        elif recv > 0 or disc > 0:
            all_rows.append({
                "date": p.date, "ref": ref,
                "trans_type": "credit",
                "debit": 0.0, "credit": recv, "discount": disc,
                "row_type": "payment"
            })

    all_rows = sorted(all_rows, key=lambda x: (
        str(x.get("date") or ""),
        "A" if x.get("row_type") in ["opening", "order", "return"] else "B"
    ))

    running = 0.0
    for row in all_rows:
        running += float(row.get("debit") or 0) - float(row.get("credit") or 0) - float(row.get("discount") or 0)
        row["running_balance"] = round(running, 3)

    frappe.response["message"] = {"status": "success", "data": all_rows}

