sales_person = frappe.form_dict.get("sales_person")
fiscal_year  = frappe.form_dict.get("fiscal_year", "2026")
if not sales_person:
    frappe.response["message"] = {"status": "error", "message": "sales_person is required"}
else:
    user = frappe.session.user
    MANAGER_ROLES = {
        "System Manager",
        "Sales Manager",
        "sales-report-allow-admin",
        "sales-report-allow-supervisor",
    }
    user_roles = set([r.role for r in frappe.db.get_all(
        "Has Role",
        filters={"parent": user, "parenttype": "User"},
        fields=["role"]
    )])
    is_manager     = bool(user_roles.intersection(MANAGER_ROLES))
    access_granted = True
    if not is_manager:
        emp = frappe.db.get_value("Employee", {"user_id": user}, "name")
        sp  = frappe.db.get_value("Sales Person", {"employee": emp}, "name") if emp else None
        if sp != sales_person:
            frappe.response["message"] = {"status": "error", "message": "غير مصرح"}
            access_granted = False
    if access_granted:
        fy = frappe.db.get_value(
            "Fiscal Year", fiscal_year,
            ["year_start_date", "year_end_date"], as_dict=True
        )
        if not fy:
            frappe.response["message"] = {
                "status" : "error",
                "message": "السنة المالية %s غير موجودة" % fiscal_year
            }
        else:
            targets = frappe.db.get_all(
                "Target Detail",
                filters={
                    "parent"     : sales_person,
                    "parenttype" : "Sales Person",
                    "fiscal_year": fiscal_year,
                },
                fields=["item_group", "target_qty", "target_amount"],
                order_by="item_group asc"
            )

            # ── SOURCE 1: ERPNext Sales Invoices ──────────────────────
            achieved_rows = frappe.db.sql("""
                SELECT
                    sii.item_group,
                    SUM(sii.qty)    AS achieved_qty,
                    SUM(sii.amount) AS achieved_amount
                FROM `tabSales Invoice Item` sii
                JOIN `tabSales Invoice` si
                    ON si.name = sii.parent
                JOIN `tabSales Team` st
                    ON st.parent      = si.name
                    AND st.parenttype = 'Sales Invoice'
                WHERE si.docstatus       = 1
                  AND st.sales_person    = %(sales_person)s
                  AND si.posting_date BETWEEN %(start)s AND %(end)s
                GROUP BY sii.item_group
            """, {
                "sales_person": sales_person,
                "start"       : fy.year_start_date,
                "end"         : fy.year_end_date,
            }, as_dict=True)

            # ── SOURCE 2: LMT Legacy Sales ────────────────────────────
            sp_emp = frappe.db.get_value("Sales Person", sales_person, "employee")
            agent_email = None
            if sp_emp:
                agent_email = frappe.db.get_value("Employee", sp_emp, "user_id")

            lmt_rows = []
            if agent_email:
                lmt_rows = frappe.db.sql("""
                    SELECT
                        itm.item_group            AS item_group,
                        SUM(oi.quantity)           AS achieved_qty,
                        SUM(oi.total)              AS achieved_amount
                    FROM `tabLMT Order Item` oi
                    JOIN `tabLMT Order` o  ON o.lmt_order_id = oi.order_id
                    JOIN `tabItem` itm     ON itm.item_name  = oi.product_name2
                    WHERE o.agent_email    = %(agent_email)s
                      AND oi.order_status != 'Canceled'
                      AND oi.free = 0
                      AND oi.order_date BETWEEN %(start)s AND %(end)s
                    GROUP BY itm.item_group
                """, {
                    "agent_email": agent_email,
                    "start"      : fy.year_start_date,
                    "end"        : fy.year_end_date,
                }, as_dict=True)

            # ── MERGE both sources ────────────────────────────────────
            ach_map = {}
            for row in achieved_rows:
                ach_map[row.item_group] = {
                    "achieved_qty":    float(row.achieved_qty or 0),
                    "achieved_amount": float(row.achieved_amount or 0),
                }
            for row in lmt_rows:
                if row.item_group in ach_map:
                    ach_map[row.item_group]["achieved_qty"]    = ach_map[row.item_group]["achieved_qty"]    + float(row.achieved_qty or 0)
                    ach_map[row.item_group]["achieved_amount"] = ach_map[row.item_group]["achieved_amount"] + float(row.achieved_amount or 0)
                else:
                    ach_map[row.item_group] = {
                        "achieved_qty":    float(row.achieved_qty or 0),
                        "achieved_amount": float(row.achieved_amount or 0),
                    }

            result = []
            for t in targets:
                ach = ach_map.get(t.item_group, {})
                result.append({
                    "item_group"     : t.item_group,
                    "target_qty"     : float(t.target_qty    or 0),
                    "target_amount"  : float(t.target_amount or 0),
                    "achieved_qty"   : float(ach.get("achieved_qty",    0) or 0),
                    "achieved_amount": float(ach.get("achieved_amount", 0) or 0),
                })
            frappe.response["message"] = {"status": "ok", "data": result}

