company = 'الشركة الليبية الحديثة'

accounts = frappe.db.sql("SELECT name, account_name, root_type, parent_account FROM tabAccount WHERE company=%s AND is_group=0 AND root_type IN ('Asset','Liability','Equity') ORDER BY root_type, name", (company,), as_dict=1)

conds = 'account = %(acct)s AND is_cancelled = 0'
if to_date:
    conds = conds + ' AND posting_date <= %(to_date)s'
if cost_center:
    conds = conds + ' AND cost_center = %(cost_center)s'

result = []
for a in accounts:
    p = {'acct': a.name, 'to_date': to_date, 'cost_center': cost_center}
    r = frappe.db.sql('SELECT IFNULL(SUM(debit),0) as d, IFNULL(SUM(credit),0) as c FROM `tabGL Entry` WHERE ' + conds, p, as_dict=1)
    dr = float(r[0].d) if r else 0
    cr = float(r[0].c) if r else 0
    if a.root_type == 'Asset':
        bal = dr - cr
    else:
        bal = cr - dr
    if bal == 0:
        continue
    result.append({
        'account': a.name,
        'account_name': a.account_name,
        'root_type': a.root_type,
        'balance': bal
    })

# Also compute net profit (Income - Expense) up to to_date
np_conds = 'gle.is_cancelled = 0'
if to_date:
    np_conds = np_conds + ' AND gle.posting_date <= %(to_date)s'
