exp = frappe.db.sql('SELECT IFNULL(SUM(gle.debit),0) - IFNULL(SUM(gle.credit),0) as bal FROM `tabGL Entry` gle INNER JOIN tabAccount a ON a.name = gle.account WHERE a.root_type = \'Expense\' AND a.company = \'الشركة الليبية الحديثة\' AND ' + np_conds, np_params, as_dict=1)

